use std::collections::HashMap;

struct CellState { 
    row: usize,
    col: usize,
    is_alive: bool,
}

struct GameBoard {
    width: usize,
    height: usize,
    current_state: HashMap<(usize, usize), bool>,
}

impl GameBoard {
    fn new(width: usize, height: usize) -> Self {
        GameBoard { 
            width, 
            height, 
            current_state: HashMap::new(),
        }
    }

    fn calculate_next_state(&self) -> HashMap<(usize, usize), bool> {
        let mut next_state = HashMap::new();
        for r in 0..self.height {
            for c in 0..self.width {
                let neighbors = self.count_live_neighbors(r, c);
                let is_alive = *self.current_state.get(&(r, c)).unwrap_or(&false);

                let next_is_alive = if !is_alive { 
                    neighbors == 3 
                } else { 
                    neighbors >= 2 && neighbors <= 3 
                };
                next_state.insert((r, c), next_is_alive);
            }
        }
        next_state
    }

    fn count_live_neighbors(&self, r: usize, c: usize) -> u8 {
        let mut count = 0;
        for dr in -1..=1 { 
            for dc in -1..=1 { 
                if dr == 0 && dc == 0 { continue; }

                let isize_r = r as isize;
                let isize_c = c as isize;

                let nr_isize = isize_r + dr;
                let nc_isize = isize_c + dc;

                if nr_isize < 0 || nc_isize < 0 { continue; }

                let nr = nr_isize.max(0) as usize;
                let nc = nc_isize.max(0) as usize;

                if nr >= self.height || nc >= self.width { continue; }

                if *self.current_state.get(&(nr, nc)).unwrap_or(&false) {
                    count += 1;
                }
            }
        }
        count
    }
}
